import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String userInput = reader.readLine();

        // Sanitize user input by allowing only alphanumeric characters and space
        if (!userInput.matches("[a-zA-Z0-9 ]+")) {
            System.out.println("Invalid input. Please enter alphanumeric characters only.");
            return;
        }

        String[] command = {"sh", "-c", "echo " + userInput}; // Use an array to pass the command safely

        Process process = Runtime.getRuntime().exec(command);

        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String outputLine;

        while ((outputLine = outputReader.readLine()) != null) {
            System.out.println(outputLine);
        }
    }
}

